class Solution {
    public int minInsertions(String s) {
        int countLeft = 0;
        int countRight = 0;
        for (int i = 0; i < s.length(); i++) {
            if (s.charAt(i) == '(') {
                countLeft++;
            } else if (s.charAt(i) == ')') {
                countRight++;
                if (countLeft > countRight) {
                    countLeft -= countRight;
                }
            }
        }
        return countLeft;
    }
}
```

